INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6daad57e-3422-4caa-9df9-4a074b8f0c39',
  '00000000-0000-0000-0000-000000000001',
  $escape$vitest + Testing Library — Query by Role, Not by Class$escape$,
  $escape$The Testing Library philosophy baked into @testing-library/react pairs naturally with vitest: test what the user sees, not how your component is built internally. Querying by CSS class or test ID ties your tests to implementation details — rename a class and your suite breaks for no user-facing reason.

Prefer `getByRole` over `getByTestId` or `querySelector`. Roles map to ARIA semantics: a `<button>` is `button`, a `<nav>` is `navigation`, an `<input type="checkbox">` is `checkbox`. When multiple elements share a role, narrow with `name` (the accessible label). Use `getByLabelText` for form fields — it validates your `<label>` wiring as a side-effect.

In vitest, this philosophy compounds with `expect` from `@testing-library/jest-dom`: matchers like `toBeVisible()`, `toBeDisabled()`, and `toHaveValue()` assert on user-observable state, not DOM structure. If a refactor doesn't change user behaviour, zero tests should break. That's the contract — and vitest's fast HMR-style watch mode makes enforcing it frictionless.$escape$,
  $escape$import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { describe, it, expect } from 'vitest';
import LoginForm from './LoginForm';

describe('LoginForm', () => {
  it('submits credentials on button click', async () => {
    const user = userEvent.setup();
    render(<LoginForm />);

    await user.type(screen.getByLabelText(/email/i), 'dev@example.com');
    await user.type(screen.getByLabelText(/password/i), 'secret');
    await user.click(screen.getByRole('button', { name: /log in/i }));

    expect(screen.getByRole('status')).toHaveTextContent(/welcome/i);
  });
});$escape$,
