INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c3be5d2d-6519-425a-87cf-9a8af6db0552',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vitest Component Testing — Render, Interact, Assert with @testing-library/react$escape$,
  $escape$Vitest integrates seamlessly with @testing-library/react via `jsdom` or `happy-dom` as the test environment. Set `environment: 'jsdom'` in `vitest.config.ts` and you're ready to mount components and drive them like a real user.

`render()` mounts your component into a virtual DOM. Query with `screen.getByRole`, `screen.getByText`, or `screen.findByText` for async updates — all return real DOM nodes, never implementation internals. Fire events with `userEvent` (preferred over `fireEvent`) since it simulates the full browser event chain including focus, keyboard, and pointer events.

Assertions live in `@testing-library/jest-dom`, which Vitest picks up automatically when you add `setupFiles: ['@testing-library/jest-dom/vitest']`. Matchers like `toBeVisible()`, `toHaveValue()`, and `toBeDisabled()` assert on what the user actually sees, not component state.

Use `vi.fn()` to stub callbacks passed as props, then assert call count and arguments with `expect(fn).toHaveBeenCalledWith(...)`. For async interactions — data fetching, transitions — await `screen.findBy*` instead of wrapping in `waitFor`; it retries automatically until the assertion passes or times out.$escape$,
  $escape$// vitest.config.ts: test: { environment: 'jsdom', setupFiles: ['@testing-library/jest-dom/vitest'] }
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { vi, expect, it } from 'vitest';
import SearchBox from './SearchBox';

it('calls onSearch with input value when form is submitted', async () => {
  const user = userEvent.setup();
  const onSearch = vi.fn();

  render(<SearchBox onSearch={onSearch} />);

  await user.type(screen.getByRole('searchbox'), 'vitest');
  await user.click(screen.getByRole('button', { name: /search/i }));

  expect(onSearch).toHaveBeenCalledWith('vitest');
  expect(screen.getByText('vitest')).toBeVisible();
});$escape$,
