INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '1f72a67b-8fc5-4f76-ae59-f45b14c905b8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vitest — Unit Testing Pure Functions and Custom Hooks with renderHook$escape$,
  $escape$Pure functions are the easiest win in Vitest: import, call, assert. No setup, no mocks, instant feedback via `vitest --watch`. Where it gets interesting is custom hooks. Vitest pairs with `@testing-library/react` to expose `renderHook`, which mounts a hook in an isolated wrapper so you can assert against its return values without a real component.

Use `act` from `@testing-library/react` (not React directly) to flush state updates — Vitest's fake timers integrate cleanly with it via `vi.useFakeTimers()`. For hooks that depend on context, pass a `wrapper` option to `renderHook` with your provider tree.

For pure functions, lean on `it.each` to table-drive edge cases — Vitest's implementation is fully typed and supports template literal test names. Avoid `describe` nesting deeper than two levels; flat test files with clear `it` descriptions read faster in Vitest's terminal reporter. Snapshot testing pure transformations with `toMatchInlineSnapshot` keeps expected output co-located with the assertion, eliminating snapshot file sprawl.$escape$,
  $escape$import { renderHook, act } from '@testing-library/react';
import { describe, it, expect, vi } from 'vitest';
import { useCounter } from './useCounter';
import { formatScore } from './utils';

describe('formatScore — pure function', () => {
  it.each([
    [0, '0 pts'],
    [1500, '1,500 pts'],
    [-10, '-10 pts'],
  ])('formatScore(%i) → %s', (input, expected) => {
    expect(formatScore(input)).toBe(expected);
  });
});

describe('useCounter', () => {
  it('increments count on tick', () => {
    vi.useFakeTimers();
    const { result } = renderHook(() => useCounter());
    act(() => { vi.advanceTimersByTime(1000); });
    expect(result.current.count).toBe(1);
    vi.useRealTimers();
  });
});$escape$,
