INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ebbbb743-c43d-44e9-a45d-492060edbef8',
  '00000000-0000-0000-0000-000000000001',
  $escape$vitest Browser Mode — E2E Critical Paths Without JSDOM Lies$escape$,
  $escape$Vitest's browser mode (`@vitest/browser`) runs tests inside a real Chromium, Firefox, or WebKit instance via a Playwright provider — no JSDOM approximations of clicks, focus, or paint. Configure it in `vitest.config.ts` with `browser: { enabled: true, provider: 'playwright', name: 'chromium' }` and scope a dedicated workspace project to auth, onboarding, and your core feature only.

Inside these tests, import `page` and `userEvent` from `@vitest/browser/context` instead of `@testing-library/user-event`. These APIs drive real browser events and await actual paint cycles. Swap `expect()` for `expect.element()` on locators — it retries until the element satisfies the matcher or times out, eliminating manual `waitFor` calls.

Structure: one file per critical path, no branching scenarios. Run them with `vitest run --project browser` in CI, isolated from your unit workspace so a JSDOM failure never blocks browser tests and vice versa. If a critical-path test is flaky, treat it as a component bug — never add `retry` to paper over it. Reserve E2E coverage for flows where a broken path means lost users: login, signup, and the one action that defines your product.$escape$,
  $escape$// vitest.config.ts
export default defineConfig({
  test: {
    workspace: [
      { extends: true, test: { name: 'unit', environment: 'jsdom' } },
      {
        extends: true,
        test: {
          name: 'browser',
          include: ['tests/e2e/**/*.test.ts'],
          browser: { enabled: true, provider: 'playwright', name: 'chromium' },
        },
      },
    ],
  },
})

// tests/e2e/auth.test.ts
import { page, userEvent } from '@vitest/browser/context'
import { render } from 'vitest-browser-react'
import { test, expect } from 'vitest'
import { LoginFlow } from '@/features/auth/LoginFlow'

test('auth critical path: valid credentials redirect to dashboard', async () => {
  render(<LoginFlow />)
  await userEvent.fill(page.getByPlaceholder('Email'), 'user@example.com')
  await userEvent.fill(page.getByPlaceholder('Password'), 'hunter2')
  await userEvent.click(page.getByRole('button', { name: 'Sign in' }))
  await expect.element(page.getByRole('heading', { name: 'Dashboard' })).toBeVisible()
})$escape$,
  $escape$typescript$escape$,
