INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '76a65e90-c8b8-4bbb-b845-4a653f0a96cc',
  '00000000-0000-0000-0000-000000000001',
  $escape$vitest + MSW — When to Mock the Network and When to Stop$escape$,
  $escape$MSW intercepts at the network level, not the module level — your fetch/axios code runs unmodified, only the response changes. In vitest, use `msw/node` with `setupServer`, not the browser service worker. Wire it up once in `setupFilesAfterFramework` or per-suite with `beforeAll`/`afterAll`, and reset handlers with `server.resetHandlers()` in `afterEach` to prevent handler bleed between tests.

When to mock: external APIs you don't own, services with rate limits, flaky third-party endpoints, or anything that would make `vitest --run` non-deterministic. When NOT to mock: your own backend endpoints during integration tests — use a real test DB and actual HTTP calls instead. Mocking your own API just means you're testing your mock, not your contract.

Avoid `vi.mock('axios')` or `vi.mock('node-fetch')` for HTTP — MSW is strictly better because it catches all transports, validates request shape, and surfaces unexpected outbound calls as test failures when you enable `server.listen({ onUnhandledRequest: 'error' })`.$escape$,
  $escape$// vitest.setup.ts
import { setupServer } from 'msw/node';
import { http, HttpResponse } from 'msw';
import { afterAll, afterEach, beforeAll } from 'vitest';

export const server = setupServer();

beforeAll(() => server.listen({ onUnhandledRequest: 'error' }));
afterEach(() => server.resetHandlers());
afterAll(() => server.close());

// in your test
server.use(
  http.get('/api/users/:id', ({ params }) =>
    HttpResponse.json({ id: params.id, name: 'Ada' })
  )
);$escape$,
